def assign_existing_projects_to_active_users(apps, schema_editor):
    project_model = apps.get_model('annotate', 'Project')
    membership_model = apps.get_model('annotate', 'ProjectMembership')
    user_app, user_model = settings.AUTH_USER_MODEL.split('.')
    user_model = apps.get_model(user_app, user_model)

    active_user_ids = list(
        user_model.objects.filter(is_active=True).values_list('id', flat=True)
    )
