    for project_id in project_model.objects.values_list('id', flat=True):
        memberships.extend(
            membership_model(project_id=project_id, user_id=user_id)
            for user_id in active_user_ids
        )
    membership_model.objects.bulk_create(memberships, ignore_conflicts=True)


